<?php $pageTitle='Creator — Beyond Market'; require __DIR__.'/includes/header.php';$id=(string)($_GET['id']??'');$creators=mread('creators.json');$products=mread('products.json');$c=null;foreach($creators as $item)if(($item['slug']??'')===$id){$c=$item;break;}if(!$c){http_response_code(404);echo '<main class="wrap section"><h1>Creator not found</h1></main>';require __DIR__.'/includes/footer.php';exit;}$mine=array_values(array_filter($products,fn($p)=>($p['creator_slug']??'')===$id));?>
<main class="wrap section"><section class="panel" style="padding:28px;display:flex;gap:22px;align-items:center;flex-wrap:wrap"><div class="avatar" style="width:90px;height:90px;font-size:42px">✦</div><div><span class="eyebrow">Creator storefront</span><h1 style="margin:7px 0"><?=me($c['name'])?> <?=$c['verified']?'✓':''?></h1><div class="muted"><?=me($c['role'])?> · <?=me($c['location'])?></div><p><?=me($c['bio'])?></p><div class="chips"><?php foreach($c['styles'] as $s):?><span class="chip"><?=me($s)?></span><?php endforeach;?></div></div></section><section class="section"><h2>Shop this creator</h2><div class="grid"><?php foreach($mine as $p):?><article class="panel product"><a href="product.php?id=<?=urlencode($p['id'])?>" style="text-decoration:none"><div class="art" style="--accent:<?=me($p['accent'])?>"><?=me($p['emoji'])?></div><div class="product-body"><h3><?=me($p['title'])?></h3><div class="price"><span><?=number_format((int)$p['price_bits'])?> bit$</span><span>$<?=me($p['price_cad'])?></span></div></div></a></article><?php endforeach;?></div></section></main><?php require __DIR__.'/includes/footer.php'; ?>